let cachedBinary = null;

function decodeBase64ToBytes() {
	if (typeof Buffer !== 'undefined') {
		return Uint8Array.from(Buffer.from(INLINE_WASM_BASE64, 'base64'));
	}
	if (typeof atob === 'function') {
		const binary = atob(INLINE_WASM_BASE64);
		const bytes = new Uint8Array(binary.length);
		for (let idx = 0; idx < binary.length; idx += 1) {
			bytes[idx] = binary.charCodeAt(idx);
		}
		return bytes;
	}
	throw new Error('Inline WASM build requires Buffer or atob support to decode base64 data');
}

export function getInlineWasmBinary() {
	if (!cachedBinary) {
		cachedBinary = decodeBase64ToBytes();
	}
	return cachedBinary;
}
